import React from "react";
import { Zoom } from "react-reveal";

const UIProjects = ({ nav, anime, img }) => {
	return (
		<>
			<Zoom
				when={anime}
				big
				spy={nav}
				duration={1200}
			>
				<img
					src={img}
					alt={`Different UI images-${img}`}
				/>
			</Zoom>
		</>
	);
};

export default UIProjects;
