import Video from "./Video";
import Footer from "./Footer";
import Explore from "./Explore";
import ScrollUp from "./ScrollUp";
import ProjectNav from "./ProjectNav";
import React, {
	useState,
	useEffect,
} from "react";
import projectsBg from "../IMAGES/ProjectsBackground.png";
// import projectsVideo from "../VIDEOS/Projects-Background.mp4";
import Masonry from "react-masonry-css";
import { UIs, PROJECTS } from "./Utils";
import MainProjects from "./MainProjects";
import UIProjects from "./UIProjects";

const Projects = () => {
	const [anime, setAnime] = useState(false);
	const [nav, setNav] = useState("All");
	const breakPoints = {
		default: 3,
		800: 2,
		450: 1,
	};
	//SET PROJECTS BASED ON NAVIGATION
	const NewProjects = PROJECTS.filter((pro) => {
		return pro?.tag?.includes(nav);
	});

	useEffect(() => {
		var observer = new IntersectionObserver(
			onIntersection,
			{
				root: null,
				threshold: 0.5,
			}
		);

		function onIntersection(entries) {
			entries.forEach(() => {
				window.addEventListener("scroll", () => {
					if (window.scrollY >= 30) {
						setAnime(true);
					}
				});
			});
		}
		observer.observe(
			document?.querySelector("main")
		);
	}, [nav]);

	return (
		<div id="projects">
			<div className="bg">
				<Video
					// vid={projectsVideo}
					img={projectsBg}
					imgName="ProjectsBg"
				/>
				<Explore />
			</div>
			<ScrollUp />
			<main>
				<ProjectNav
					anime={anime}
					nav={nav}
					setNav={setNav}
				/>
				<section>
					{nav === "UI/UX" ? (
						<Masonry
							breakpointCols={breakPoints}
							className="UI-UX"
							columnClassName="UI_image"
						>
							{UIs?.map((img) => {
								return (
									<UIProjects
										img={img}
										anime={anime}
										nav={nav}
									/>
								);
							})}
						</Masonry>
					) : (
						<div className="gridSection">
							{NewProjects.map((project) => {
								return (
									<MainProjects
										key={project.id}
										project={project}
										anime={anime}
										nav={nav}
									/>
								);
							})}
						</div>
					)}
				</section>
			</main>
			<Footer />
		</div>
	);
};

export default Projects;
